LAYER
  NAME "promedio_multianual_evapotranspiracion_real_acumulada"
  GROUP "Evapotranspiración regiones de Cusco y Apurímac"
  STATUS off
  DATA "archivos/raster/promedio_multianual_evapotranspiracion_real_acumulada.img"
  TYPE RASTER
  TRANSPARENCY 100
  DUMP true
  HEADER   "plantillas/inicio.html"
  TEMPLATE "plantillas/raster.html"
  FOOTER   "plantillas/fin.html" 
  PROJECTION
	"init=epsg:32718"
  END
  METADATA
	"wms_encoding" "LATIN1"
	"layer_encoding" "LATIN1"
	"wms_group_title" "Evapotranspiración regiones de Cusco y Apurímac"
	"queryable" "true"
	"wms_metadataurl_type" "TC211"
	"wms_title" "Promedio multianual de la evapotranspiración real acumulada"
	"wms_abstract" "Promedio multianual de la evapotranspiración real acumulada - Copyright © Servicio Nacional de Meteorología e Hidrología - SENAMHI, fecha: Junio 2010 :: http://www.senamhi.gob.pe, Publicado por el  para el Programa de Adaptación al Cambio Climático  - PACC Perú 2013 :: http://www.paccperu.org.pe"
	"wms_dataurl_href" "../descargar/promedio_multianual_evapotranspiracion_real_acumulada.rar" 
